#include <iostream>
#include <string>

int main() {
    std::string s1 = "Hello";
    std::string s2 = "World";
    std::string result = s1 + " " + s2;
    std::cout << result << std::endl;        // Hello World
    std::cout << result.length() << std::endl; // 11
    return 0;
}

