#include <iostream>
#include <string>

int main() {
    std::string s = "Programming";
    std::cout << s[0] << std::endl;          // P
    std::cout << s.back() << std::endl;      // g (C++11)
    std::cout << s.substr(0, 4) << std::endl; // Prog
    std::cout << s.substr(4) << std::endl;    // ramming
    return 0;
}

#include <iostream>
#include <format>

int main() {
    std::string name = "Alice";
    int age = 25;
    std::cout << std::format("My name is {} and I am {} years old.", name, age) << std::endl;
    return 0;
}

